SELECT fia_plot_number, plot_area
FROM fia_plots
WHERE county_id = 1;

SELECT AVG(carbon_density) AS average_carbon_density
FROM county_statistics
WHERE year = 2022;

SELECT county_id, COUNT(plot_id) AS total_plots
FROM fia_plots
GROUP BY county_id;

SELECT AVG(mean_carbon) AS average_carbon
FROM carbon_measurements
WHERE measurement_year = 2022;
